import type {
    NewWorkoutTemplateWithBlocks,
    TemplateBlock,
    TemplateStrengthSet,
    WorkoutTemplate,
    WorkoutTemplateWithBlocks,
} from '../types/health.js';
import type { DbDriver } from '../types/db.js';
import { NOOP_LOGGER, type RepoLogger } from '../types/logger.js';
import { uuidv7 } from '../utils/uuid.js';
import { NotFoundError } from '../api/response-helpers.js';

const TEMPLATE_COLUMNS = `id, name, notes, use_count, last_used_at, archived_at, created_at, updated_at`;
const TEMPLATE_SET_COLUMNS = `id, template_id, position, exercise_id, target_set_count,
    target_reps, target_weight_kg, target_rpe, target_rest_s, notes`;
const TEMPLATE_BLOCK_COLUMNS = `id, template_id, position, parent_label, kind, modality,
    target_duration_s, target_distance_m, target_intensity, notes`;

async function loadTemplateChildren(
    driver: DbDriver,
    templateId: string,
): Promise<{ strength_sets: TemplateStrengthSet[]; blocks: TemplateBlock[] }> {
    const strength_sets = await driver.query<TemplateStrengthSet>(
        `SELECT ${TEMPLATE_SET_COLUMNS} FROM template_strength_sets WHERE template_id = ? ORDER BY position ASC`,
        templateId,
    );
    const blocks = await driver.query<TemplateBlock>(
        `SELECT ${TEMPLATE_BLOCK_COLUMNS} FROM template_blocks WHERE template_id = ? ORDER BY position ASC`,
        templateId,
    );
    return { strength_sets, blocks };
}

async function insertTemplateChildren(
    driver: DbDriver,
    templateId: string,
    payload: NewWorkoutTemplateWithBlocks,
): Promise<void> {
    for (const [index, s] of payload.strength_sets.entries()) {
        await driver.execute(
            `INSERT INTO template_strength_sets (
                id, template_id, position, exercise_id, target_set_count,
                target_reps, target_weight_kg, target_rpe, target_rest_s, notes
            ) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?)`,
            uuidv7(),
            templateId,
            index,
            s.exercise_id,
            s.target_set_count,
            s.target_reps ?? null,
            s.target_weight_kg ?? null,
            s.target_rpe ?? null,
            s.target_rest_s ?? null,
            s.notes ?? null,
        );
    }
    for (const [index, b] of (payload.blocks ?? []).entries()) {
        await driver.execute(
            `INSERT INTO template_blocks (
                id, template_id, position, parent_label, kind, modality,
                target_duration_s, target_distance_m, target_intensity, notes
            ) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?)`,
            uuidv7(),
            templateId,
            index,
            b.parent_label ?? null,
            b.kind,
            b.modality ?? null,
            b.target_duration_s ?? null,
            b.target_distance_m ?? null,
            b.target_intensity ?? null,
            b.notes ?? null,
        );
    }
}

export interface WorkoutTemplateRepositoryOptions {
    log?: RepoLogger;
}

export function createWorkoutTemplateRepository(driver: DbDriver, options: WorkoutTemplateRepositoryOptions = {}) {
    const log = options.log ?? NOOP_LOGGER;
    const repository = {
        async findById(id: string): Promise<WorkoutTemplateWithBlocks | null> {
            log.debug('workoutTemplates.findById', { id });
            const template = await driver.queryOne<WorkoutTemplate>(
                `SELECT ${TEMPLATE_COLUMNS} FROM workout_templates WHERE id = ?`,
                [id],
            );
            if (!template) return null;
            const children = await loadTemplateChildren(driver, template.id);
            return { ...template, ...children };
        },

        async getById(id: string): Promise<WorkoutTemplateWithBlocks> {
            log.debug('workoutTemplates.getById', { id });
            const template = await driver.queryOne<WorkoutTemplate>(
                `SELECT ${TEMPLATE_COLUMNS} FROM workout_templates WHERE id = ?`,
                [id],
                { notFound: () => new NotFoundError(`Workout template ${id} not found`) },
            );
            const children = await loadTemplateChildren(driver, template.id);
            return { ...template, ...children };
        },

        async list({ limit = 50, includeArchived = false }: { limit?: number; includeArchived?: boolean } = {}): Promise<WorkoutTemplate[]> {
            log.debug('workoutTemplates.list', { limit, includeArchived });
            const where = includeArchived ? '' : 'WHERE archived_at IS NULL';
            return driver.query<WorkoutTemplate>(
                `SELECT ${TEMPLATE_COLUMNS} FROM workout_templates ${where}
                 ORDER BY use_count DESC, last_used_at DESC, name ASC
                 LIMIT ?`,
                limit,
            );
        },

        async create(payload: NewWorkoutTemplateWithBlocks): Promise<WorkoutTemplateWithBlocks> {
            if (!payload.name?.trim()) throw new Error('Template name is required');
            if (!payload.strength_sets?.length && !payload.blocks?.length) {
                throw new Error('Template must have at least one strength set or block');
            }
            const id = uuidv7();
            log.debug('workoutTemplates.create: BEGIN', { id, name: payload.name, setCount: payload.strength_sets.length, blockCount: payload.blocks?.length ?? 0 });

            await driver.execute('BEGIN TRANSACTION');
            try {
                await driver.execute(
                    `INSERT INTO workout_templates (id, name, notes) VALUES (?, ?, ?)`,
                    id,
                    payload.name.trim(),
                    payload.notes ?? null,
                );
                await insertTemplateChildren(driver, id, payload);
                await driver.execute('COMMIT');
                log.debug('workoutTemplates.create: COMMIT', { id });
            } catch (err) {
                await driver.execute('ROLLBACK');
                log.warn('workoutTemplates.create: ROLLBACK', { id, error: err instanceof Error ? err.message : String(err) });
                throw err;
            }
            return repository.getById(id);
        },

        async update(id: string, updates: Partial<NewWorkoutTemplateWithBlocks>): Promise<WorkoutTemplateWithBlocks> {
            await repository.getById(id);
            log.debug('workoutTemplates.update: BEGIN', { id, fields: Object.keys(updates) });

            // Validate before opening the transaction so a bad payload fails fast.
            if (updates.name !== undefined && !updates.name.trim()) {
                throw new Error('Template name is required');
            }

            await driver.execute('BEGIN TRANSACTION');
            try {
                const fields: string[] = [];
                const values: unknown[] = [];
                const allowed = ['name', 'notes'] as const;
                for (const field of allowed) {
                    if (updates[field] !== undefined) {
                        fields.push(`${field} = ?`);
                        const value = updates[field] ?? null;
                        values.push(field === 'name' && typeof value === 'string' ? value.trim() : value);
                    }
                }
                if (fields.length > 0) {
                    fields.push("updated_at = datetime('now')");
                    values.push(id);
                    await driver.execute(`UPDATE workout_templates SET ${fields.join(', ')} WHERE id = ?`, ...values);
                }

                if (updates.strength_sets !== undefined || updates.blocks !== undefined) {
                    if (updates.strength_sets !== undefined) {
                        await driver.execute('DELETE FROM template_strength_sets WHERE template_id = ?', id);
                    }
                    if (updates.blocks !== undefined) {
                        await driver.execute('DELETE FROM template_blocks WHERE template_id = ?', id);
                    }
                    await insertTemplateChildren(driver, id, {
                        name: updates.name ?? '',
                        notes: updates.notes,
                        strength_sets: updates.strength_sets ?? [],
                        blocks: updates.blocks ?? [],
                    });
                    const empty = (updates.strength_sets ?? []).length === 0 && (updates.blocks ?? []).length === 0;
                    if (updates.strength_sets !== undefined && updates.blocks !== undefined && empty) {
                        throw new Error('Template must have at least one strength set or block');
                    }
                }
                await driver.execute('COMMIT');
                log.debug('workoutTemplates.update: COMMIT', { id });
            } catch (err) {
                await driver.execute('ROLLBACK');
                log.warn('workoutTemplates.update: ROLLBACK', { id, error: err instanceof Error ? err.message : String(err) });
                throw err;
            }
            return repository.getById(id);
        },

        async archive(id: string): Promise<WorkoutTemplate> {
            await repository.getById(id);
            log.debug('workoutTemplates.archive', { id });
            await driver.execute(
                `UPDATE workout_templates SET archived_at = datetime('now'), updated_at = datetime('now') WHERE id = ?`,
                id,
            );
            return driver.queryOne<WorkoutTemplate>(
                `SELECT ${TEMPLATE_COLUMNS} FROM workout_templates WHERE id = ?`,
                [id],
                { notFound: () => new NotFoundError(`Workout template ${id} not found`) },
            );
        },

        async unarchive(id: string): Promise<WorkoutTemplate> {
            await repository.getById(id);
            log.debug('workoutTemplates.unarchive', { id });
            await driver.execute(
                `UPDATE workout_templates SET archived_at = NULL, updated_at = datetime('now') WHERE id = ?`,
                id,
            );
            return driver.queryOne<WorkoutTemplate>(
                `SELECT ${TEMPLATE_COLUMNS} FROM workout_templates WHERE id = ?`,
                [id],
                { notFound: () => new NotFoundError(`Workout template ${id} not found`) },
            );
        },

        async delete(id: string): Promise<boolean> {
            log.debug('workoutTemplates.delete', { id });
            const result = await driver.execute(`DELETE FROM workout_templates WHERE id = ?`, id);
            return result.changes > 0;
        },

        async touchUse(id: string): Promise<void> {
            log.debug('workoutTemplates.touchUse', { id });
            await driver.execute(
                `UPDATE workout_templates SET use_count = use_count + 1, last_used_at = datetime('now'), updated_at = datetime('now') WHERE id = ?`,
                id,
            );
        },
    };

    return repository;
}

export type WorkoutTemplateRepository = ReturnType<typeof createWorkoutTemplateRepository>;
