import type { Exercise, NewExercise } from '../types/health.js';
import type { DbDriver } from '../types/db.js';
import { NOOP_LOGGER, type RepoLogger } from '../types/logger.js';
import { uuidv7 } from '../utils/uuid.js';
import { NotFoundError } from '../api/response-helpers.js';

const EXERCISE_COLUMNS = `
    id, canonical_name, display_name, category, default_unit,
    tracks_reps, tracks_weight, tracks_duration,
    notes, use_count, last_used_at, archived_at, created_at, updated_at
`;

function normalizeName(value: string): string {
    return value.trim().toLowerCase().replace(/\s+/g, ' ');
}

export interface ExerciseRepositoryOptions {
    log?: RepoLogger;
}

export function createExerciseRepository(driver: DbDriver, options: ExerciseRepositoryOptions = {}) {
    const log = options.log ?? NOOP_LOGGER;
    const repository = {
        async findById(id: string): Promise<Exercise | null> {
            log.debug('exercises.findById', { id });
            return driver.queryOne<Exercise>(`SELECT ${EXERCISE_COLUMNS} FROM exercises WHERE id = ?`, [id]);
        },

        async getById(id: string): Promise<Exercise> {
            log.debug('exercises.getById', { id });
            return driver.queryOne<Exercise>(`SELECT ${EXERCISE_COLUMNS} FROM exercises WHERE id = ?`, [id], {
                notFound: () => new NotFoundError(`Exercise ${id} not found`),
            });
        },

        async findByCanonicalName(canonicalName: string): Promise<Exercise | null> {
            log.debug('exercises.findByCanonicalName', { canonicalName });
            return driver.queryOne<Exercise>(
                `SELECT ${EXERCISE_COLUMNS} FROM exercises WHERE canonical_name = ?`,
                [canonicalName],
            );
        },

        async list({ limit = 100, includeArchived = false }: { limit?: number; includeArchived?: boolean } = {}): Promise<Exercise[]> {
            log.debug('exercises.list', { limit, includeArchived });
            const where = includeArchived ? '' : 'WHERE archived_at IS NULL';
            return driver.query<Exercise>(
                `SELECT ${EXERCISE_COLUMNS} FROM exercises ${where}
                 ORDER BY use_count DESC, last_used_at DESC, display_name ASC
                 LIMIT ?`,
                limit,
            );
        },

        async search(query: string, limit = 10): Promise<Exercise[]> {
            log.debug('exercises.search', { query, limit });
            const normalized = normalizeName(query);
            if (!normalized) return repository.list({ limit });
            return driver.query<Exercise>(
                `
                    SELECT ${EXERCISE_COLUMNS},
                           CASE
                                WHEN LOWER(display_name) = ? THEN 0
                                WHEN LOWER(display_name) LIKE ? THEN 1
                                WHEN LOWER(canonical_name) LIKE ? THEN 2
                                ELSE 3
                           END AS rank
                    FROM exercises
                    WHERE archived_at IS NULL
                      AND (LOWER(display_name) LIKE ? OR LOWER(canonical_name) LIKE ?)
                    ORDER BY rank ASC, use_count DESC, last_used_at DESC, display_name ASC
                    LIMIT ?
                `,
                normalized,
                `${normalized}%`,
                `${normalized}%`,
                `%${normalized}%`,
                `%${normalized}%`,
                limit,
            );
        },

        async create(payload: NewExercise): Promise<Exercise> {
            if (!payload.canonical_name?.trim()) throw new Error('canonical_name is required');
            if (!payload.display_name?.trim()) throw new Error('display_name is required');

            const id = uuidv7();
            log.debug('exercises.create', { id, canonical_name: payload.canonical_name });
            await driver.execute(
                `INSERT INTO exercises (
                    id, canonical_name, display_name, category, default_unit,
                    tracks_reps, tracks_weight, tracks_duration,
                    notes, use_count, last_used_at, archived_at
                ) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)`,
                id,
                payload.canonical_name.trim(),
                payload.display_name.trim(),
                payload.category,
                payload.default_unit,
                payload.tracks_reps,
                payload.tracks_weight,
                payload.tracks_duration,
                payload.notes ?? null,
                payload.use_count ?? 0,
                payload.last_used_at ?? null,
                payload.archived_at ?? null,
            );
            return repository.getById(id);
        },

        async update(id: string, updates: Partial<NewExercise>): Promise<Exercise> {
            await repository.getById(id);
            log.debug('exercises.update', { id, fields: Object.keys(updates) });

            // Validate before building the SET clause so a bad payload never reaches SQL.
            if (updates.canonical_name !== undefined && !updates.canonical_name.trim()) {
                throw new Error('canonical_name is required');
            }
            if (updates.display_name !== undefined && !updates.display_name.trim()) {
                throw new Error('display_name is required');
            }

            const fields: string[] = [];
            const values: unknown[] = [];
            const allowed = [
                'canonical_name', 'display_name', 'category', 'default_unit',
                'tracks_reps', 'tracks_weight', 'tracks_duration', 'notes',
            ] as const;
            for (const field of allowed) {
                if (updates[field] !== undefined) {
                    fields.push(`${field} = ?`);
                    const value = updates[field] ?? null;
                    values.push(
                        (field === 'canonical_name' || field === 'display_name') && typeof value === 'string'
                            ? value.trim()
                            : value,
                    );
                }
            }

            if (fields.length > 0) {
                fields.push("updated_at = datetime('now')");
                values.push(id);
                await driver.execute(`UPDATE exercises SET ${fields.join(', ')} WHERE id = ?`, ...values);
            }
            return repository.getById(id);
        },

        async archive(id: string): Promise<Exercise> {
            await repository.getById(id);
            log.debug('exercises.archive', { id });
            await driver.execute(
                `UPDATE exercises SET archived_at = datetime('now'), updated_at = datetime('now') WHERE id = ?`,
                id,
            );
            return repository.getById(id);
        },

        async unarchive(id: string): Promise<Exercise> {
            await repository.getById(id);
            log.debug('exercises.unarchive', { id });
            await driver.execute(
                `UPDATE exercises SET archived_at = NULL, updated_at = datetime('now') WHERE id = ?`,
                id,
            );
            return repository.getById(id);
        },

        async touchUse(id: string): Promise<void> {
            log.debug('exercises.touchUse', { id });
            await driver.execute(
                `UPDATE exercises SET use_count = use_count + 1, last_used_at = datetime('now'), updated_at = datetime('now') WHERE id = ?`,
                id,
            );
        },
    };

    return repository;
}

export type ExerciseRepository = ReturnType<typeof createExerciseRepository>;
