import type { DbDriver } from '../types/db.js';
import type { Person, Interaction, ImportantDate, NewPerson, NewInteraction, NewImportantDate } from '../types/social.js';
import { NOOP_LOGGER, type RepoLogger } from '../types/logger.js';
import { uuidv7 } from '../utils/uuid.js';
import { NotFoundError } from '../api/response-helpers.js';

export interface SocialRepositoryOptions {
    log?: RepoLogger;
}

export function createSocialRepository(driver: DbDriver, options: SocialRepositoryOptions = {}) {
    const log = options.log ?? NOOP_LOGGER;
    const repository = {
        // --- People ---
        async getAllPeople(): Promise<Person[]> {
            log.debug('social.getAllPeople');
            return driver.query<Person>('SELECT * FROM people ORDER BY name');
        },

        async findPersonById(id: string): Promise<Person | null> {
            log.debug('social.findPersonById', { id });
            return driver.queryOne<Person>('SELECT * FROM people WHERE id = ?', [id]);
        },

        async getPersonById(id: string): Promise<Person> {
            log.debug('social.getPersonById', { id });
            return driver.queryOne<Person>('SELECT * FROM people WHERE id = ?', [id], {
                notFound: () => new NotFoundError(`Person ${id} not found`),
            });
        },

        async createPerson(person: NewPerson): Promise<Person> {
            const id = uuidv7();
            log.debug('social.createPerson', { id });
            await driver.execute(
                'INSERT INTO people (id, name, notes, relationship, photo_url) VALUES (?, ?, ?, ?, ?)',
                id,
                person.name,
                person.notes ?? null,
                person.relationship ?? null,
                person.photo_url ?? null,
            );
            return driver.queryOne<Person>('SELECT * FROM people WHERE id = ?', [id], {
                notFound: () => new Error(`Failed to load created person: ${id}`),
            });
        },

        async updatePerson(id: string, updates: Partial<NewPerson>): Promise<Person> {
            await repository.getPersonById(id);
            log.debug('social.updatePerson', { id, fields: Object.keys(updates) });

            const fields: string[] = [];
            const values: unknown[] = [];
            const allowed = ['name', 'notes', 'relationship', 'photo_url'] as const;
            for (const field of allowed) {
                if (updates[field] !== undefined) {
                    fields.push(`${field} = ?`);
                    values.push(updates[field] ?? null);
                }
            }

            if (fields.length > 0) {
                fields.push("updated_at = datetime('now')");
                values.push(id);
                await driver.execute(`UPDATE people SET ${fields.join(', ')} WHERE id = ?`, ...values);
            }

            return driver.queryOne<Person>('SELECT * FROM people WHERE id = ?', [id], {
                notFound: () => new Error(`Person ${id} not found after update`),
            });
        },

        async deletePerson(id: string): Promise<boolean> {
            log.debug('social.deletePerson', { id });
            const result = await driver.execute('DELETE FROM people WHERE id = ?', id);
            return result.changes > 0;
        },

        // --- Important Dates ---
        async getDatesByPersonId(personId: string): Promise<ImportantDate[]> {
            log.debug('social.getDatesByPersonId', { personId });
            return driver.query<ImportantDate>('SELECT * FROM important_dates WHERE person_id = ? ORDER BY date DESC', personId);
        },

        async findImportantDateById(id: string): Promise<ImportantDate | null> {
            log.debug('social.findImportantDateById', { id });
            return driver.queryOne<ImportantDate>('SELECT * FROM important_dates WHERE id = ?', [id]);
        },

        async getImportantDateById(id: string): Promise<ImportantDate> {
            log.debug('social.getImportantDateById', { id });
            return driver.queryOne<ImportantDate>('SELECT * FROM important_dates WHERE id = ?', [id], {
                notFound: () => new NotFoundError(`Important date ${id} not found`),
            });
        },

        async createImportantDate(date: NewImportantDate): Promise<ImportantDate> {
            const id = uuidv7();
            log.debug('social.createImportantDate', { id, person_id: date.person_id });
            await driver.execute(
                'INSERT INTO important_dates (id, person_id, label, date, recurring) VALUES (?, ?, ?, ?, ?)',
                id,
                date.person_id,
                date.label,
                date.date,
                date.recurring ? 1 : 0,
            );
            return driver.queryOne<ImportantDate>('SELECT * FROM important_dates WHERE id = ?', [id], {
                notFound: () => new Error(`Failed to load created date: ${id}`),
            });
        },

        async updateImportantDate(id: string, updates: Partial<NewImportantDate>): Promise<ImportantDate> {
            await repository.getImportantDateById(id);
            log.debug('social.updateImportantDate', { id, fields: Object.keys(updates) });

            const fields: string[] = [];
            const values: unknown[] = [];
            if ('label' in updates) {
                fields.push('label = ?');
                values.push(updates.label ?? null);
            }
            if ('date' in updates) {
                fields.push('date = ?');
                values.push(updates.date ?? null);
            }
            if ('recurring' in updates) {
                fields.push('recurring = ?');
                values.push(updates.recurring ? 1 : 0);
            }

            if (fields.length > 0) {
                values.push(id);
                await driver.execute(`UPDATE important_dates SET ${fields.join(', ')} WHERE id = ?`, ...values);
            }

            return driver.queryOne<ImportantDate>('SELECT * FROM important_dates WHERE id = ?', [id], {
                notFound: () => new Error(`Important date ${id} not found after update`),
            });
        },

        async deleteImportantDate(id: string): Promise<boolean> {
            log.debug('social.deleteImportantDate', { id });
            const result = await driver.execute('DELETE FROM important_dates WHERE id = ?', id);
            return result.changes > 0;
        },

        // --- Interactions ---
        async getInteractionsByPersonId(personId: string): Promise<Interaction[]> {
            log.debug('social.getInteractionsByPersonId', { personId });
            return driver.query<Interaction>(
                'SELECT * FROM interactions WHERE person_id = ? ORDER BY date DESC',
                personId
            );
        },

        async findInteractionById(id: string): Promise<Interaction | null> {
            log.debug('social.findInteractionById', { id });
            return driver.queryOne<Interaction>('SELECT * FROM interactions WHERE id = ?', [id]);
        },

        async getInteractionById(id: string): Promise<Interaction> {
            log.debug('social.getInteractionById', { id });
            return driver.queryOne<Interaction>('SELECT * FROM interactions WHERE id = ?', [id], {
                notFound: () => new NotFoundError(`Interaction ${id} not found`),
            });
        },

        async createInteraction(interaction: NewInteraction): Promise<Interaction> {
            const id = uuidv7();
            log.debug('social.createInteraction', { id, person_id: interaction.person_id });
            await driver.execute(
                'INSERT INTO interactions (id, person_id, type, date, notes) VALUES (?, ?, ?, ?, ?)',
                id,
                interaction.person_id,
                interaction.type,
                interaction.date,
                interaction.notes ?? null,
            );
            return driver.queryOne<Interaction>('SELECT * FROM interactions WHERE id = ?', [id], {
                notFound: () => new Error(`Failed to load created interaction: ${id}`),
            });
        },

        async updateInteraction(id: string, updates: Partial<NewInteraction>): Promise<Interaction> {
            await repository.getInteractionById(id);
            log.debug('social.updateInteraction', { id, fields: Object.keys(updates) });

            const fields: string[] = [];
            const values: unknown[] = [];
            const allowed = ['type', 'date', 'notes'] as const;
            for (const field of allowed) {
                if (updates[field] !== undefined) {
                    fields.push(`${field} = ?`);
                    values.push(updates[field] ?? null);
                }
            }

            if (fields.length > 0) {
                values.push(id);
                await driver.execute(`UPDATE interactions SET ${fields.join(', ')} WHERE id = ?`, ...values);
            }

            return driver.queryOne<Interaction>('SELECT * FROM interactions WHERE id = ?', [id], {
                notFound: () => new Error(`Interaction ${id} not found after update`),
            });
        },

        async deleteInteraction(id: string): Promise<boolean> {
            log.debug('social.deleteInteraction', { id });
            const result = await driver.execute('DELETE FROM interactions WHERE id = ?', id);
            return result.changes > 0;
        },
    };

    return repository;
}

export type SocialRepository = ReturnType<typeof createSocialRepository>;
