import type { Goal, NewGoal } from '../types/goals.js';
import type { GoalRepository } from '../repositories/goal.repository.js';
import { AbstractRouteResponses, type ApiResponse, type RouteContext } from './response-helpers.js';

export type GoalRouteKey =
    | 'GET /'
    | 'GET /:id'
    | 'POST /'
    | 'PATCH /:id'
    | 'DELETE /:id';

export const GOAL_ROUTE_KEYS: readonly GoalRouteKey[] = [
    'GET /',
    'GET /:id',
    'POST /',
    'PATCH /:id',
    'DELETE /:id',
] as const;

export interface IGoalRoutes {
    'GET /'(ctx: RouteContext): Promise<ApiResponse>;
    'GET /:id'(ctx: RouteContext): Promise<ApiResponse>;
    'POST /'(ctx: RouteContext): Promise<ApiResponse>;
    'PATCH /:id'(ctx: RouteContext): Promise<ApiResponse>;
    'DELETE /:id'(ctx: RouteContext): Promise<ApiResponse>;
}

export abstract class AbstractGoalRoutes extends AbstractRouteResponses implements IGoalRoutes {
    protected abstract readonly repo: GoalRepository;

    async 'GET /'(): Promise<ApiResponse> {
        return this.ok(await this.repo.getAll());
    }

    async 'GET /:id'({ params }: RouteContext): Promise<ApiResponse> {
        return this.ok(await this.repo.getGoalById(params.id));
    }

    async 'POST /'({ body }: RouteContext): Promise<ApiResponse> {
        const b = (body ?? {}) as Partial<NewGoal>;
        if (!b.title || typeof b.title !== 'string' || !b.title.trim()) {
            return this.badRequest('Title is required');
        }
        const goal = await this.repo.create({
            title: b.title.trim(),
            description: typeof b.description === 'string' ? b.description : undefined,
            parent_id: typeof b.parent_id === 'string' ? b.parent_id : undefined,
            status: b.status ?? 'ACTIVE',
        });
        return this.created(goal);
    }

    async 'PATCH /:id'({ params, body }: RouteContext): Promise<ApiResponse> {
        const b = (body ?? {}) as Record<string, unknown>;
        const updated = await this.repo.update(params.id, {
            title: typeof b.title === 'string' ? b.title : undefined,
            description: typeof b.description === 'string' ? b.description : undefined,
            status: b.status as Goal['status'] | undefined,
        });
        return this.ok(updated);
    }

    async 'DELETE /:id'({ params }: RouteContext): Promise<ApiResponse> {
        await this.repo.getGoalById(params.id);
        await this.repo.delete(params.id);
        return this.noContent();
    }
}
