import type {
    AiEstimation,
    ConsumptionEntry,
    FoodItem,
    MealType,
    NewAiEstimation,
    NewFoodItem,
} from '../types/health.js';
import type { DbDriver } from '../types/db.js';
import { NOOP_LOGGER, type RepoLogger } from '../types/logger.js';
import { uuidv7 } from '../utils/uuid.js';
import { NotFoundError } from '../api/response-helpers.js';
import { isImagePathReferenced } from './image-references.js';
import {
    computeSnapshotMacros,
    insertConsumptionEntryAndRecompute,
} from './consumption-entries.repository.js';

function normalizeFoodName(value: string): string {
    return value.trim().toLowerCase().replace(/\s+/g, ' ');
}

const FOOD_ITEM_COLUMNS = `
    id, canonical_name, display_name, brand, barcode,
    source, source_ref, base_amount, base_unit, default_serving_amount,
    serving_label, serving_quantity,
    calories_per_base, protein_g_per_base, carbs_g_per_base, fat_g_per_base,
    fiber_g_per_base, sugar_g_per_base, sodium_mg_per_base,
    use_count, last_used_at, raw_json, image_path, archived_at, created_at, updated_at
`;

export type FoodItemUpsertKey =
    | { kind: 'id'; id: string }
    | { kind: 'barcode'; barcode: string }
    | { kind: 'source_ref'; source: FoodItem['source']; source_ref: string }
    | { kind: 'name'; canonical_name: string; brand: string | null; source: FoodItem['source'] };

function resolveUpsertKey(item: NewFoodItem & { id?: string }): FoodItemUpsertKey {
    if (item.id) return { kind: 'id', id: item.id };
    if (item.barcode) return { kind: 'barcode', barcode: item.barcode };
    if (item.source_ref && item.source !== 'ai_estimate') {
        return { kind: 'source_ref', source: item.source, source_ref: item.source_ref };
    }
    return {
        kind: 'name',
        canonical_name: normalizeFoodName(item.canonical_name),
        brand: item.brand ?? null,
        source: item.source,
    };
}

/**
 * Optional callbacks the host (server) wires into the repository factory.
 * Browser/PWA callers leave this unset; the server passes a callback that
 * removes the on-disk image directory. Story 130.
 */
export interface FoodItemRepositoryOptions {
    log?: RepoLogger;
    /**
     * Fired after an UPDATE drops the previous `image_path` and that path is
     * no longer referenced by any other row (`food_items` / `meals` /
     * `ai_estimations`). Best-effort — errors thrown from the callback are
     * caught and swallowed; the row update is the primary intent.
     */
    onImageReleased?: (imagePath: string) => Promise<void> | void;
}

export function createFoodItemRepository(driver: DbDriver, options: FoodItemRepositoryOptions = {}) {
    const log = options.log ?? NOOP_LOGGER;
    const onImageReleased = options.onImageReleased;
    const repository = {
        // ──────────────────────────────────────────────────────────
        // Reads
        // ──────────────────────────────────────────────────────────

        async findById(id: string): Promise<FoodItem | null> {
            log.debug('foodItems.findById', { id });
            return driver.queryOne<FoodItem>(`SELECT ${FOOD_ITEM_COLUMNS} FROM food_items WHERE id = ?`, [id]);
        },

        async getById(id: string): Promise<FoodItem> {
            log.debug('foodItems.getById', { id });
            return driver.queryOne<FoodItem>(`SELECT ${FOOD_ITEM_COLUMNS} FROM food_items WHERE id = ?`, [id], {
                notFound: () => new NotFoundError(`Food item ${id} not found`),
            });
        },

        async findByBarcode(barcode: string): Promise<FoodItem | null> {
            log.debug('foodItems.findByBarcode', { barcode });
            return driver.queryOne<FoodItem>(`SELECT ${FOOD_ITEM_COLUMNS} FROM food_items WHERE barcode = ?`, [barcode]);
        },

        async findBySourceRef(source: FoodItem['source'], sourceRef: string): Promise<FoodItem | null> {
            log.debug('foodItems.findBySourceRef', { source, sourceRef });
            return driver.queryOne<FoodItem>(`SELECT ${FOOD_ITEM_COLUMNS} FROM food_items WHERE source = ? AND source_ref = ?`, [source, sourceRef]);
        },

        async search(query: string, limit = 10): Promise<FoodItem[]> {
            const normalized = normalizeFoodName(query);
            if (!normalized) {
                return repository.frequent(limit);
            }
            return driver.query<FoodItem>(
                `
                    SELECT ${FOOD_ITEM_COLUMNS},
                           CASE
                                WHEN canonical_name = ? THEN 0
                                WHEN canonical_name LIKE ? THEN 1
                                WHEN canonical_name LIKE ? THEN 2
                                ELSE 3
                           END AS rank
                    FROM food_items
                    WHERE archived_at IS NULL AND canonical_name LIKE ?
                    ORDER BY rank ASC, use_count DESC, last_used_at DESC, display_name ASC
                    LIMIT ?
                `,
                normalized,
                `${normalized}%`,
                `% ${normalized}%`,
                `%${normalized}%`,
                limit,
            );
        },

        async frequent(limit = 10): Promise<FoodItem[]> {
            return driver.query<FoodItem>(
                `SELECT ${FOOD_ITEM_COLUMNS} FROM food_items WHERE archived_at IS NULL ORDER BY use_count DESC, last_used_at DESC, display_name ASC LIMIT ?`,
                limit,
            );
        },

        async recent(limit = 10): Promise<FoodItem[]> {
            return driver.query<FoodItem>(
                `SELECT ${FOOD_ITEM_COLUMNS} FROM food_items WHERE archived_at IS NULL ORDER BY last_used_at DESC, use_count DESC, display_name ASC LIMIT ?`,
                limit,
            );
        },

        // ──────────────────────────────────────────────────────────
        // Writes
        // ──────────────────────────────────────────────────────────

        async create(item: NewFoodItem): Promise<FoodItem> {
            const id = uuidv7();
            log.debug('foodItems.create', { id, source: item.source });
            await driver.execute(
                `
                    INSERT INTO food_items (
                        id, canonical_name, display_name, brand, barcode,
                        source, source_ref, base_amount, base_unit, default_serving_amount,
                        serving_label, serving_quantity,
                        calories_per_base, protein_g_per_base, carbs_g_per_base, fat_g_per_base,
                        fiber_g_per_base, sugar_g_per_base, sodium_mg_per_base,
                        use_count, last_used_at, raw_json, image_path
                    ) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
                `,
                id,
                normalizeFoodName(item.canonical_name || item.display_name),
                item.display_name.trim(),
                item.brand ?? null,
                item.barcode ?? null,
                item.source,
                item.source_ref ?? null,
                item.base_amount,
                item.base_unit,
                item.default_serving_amount ?? null,
                item.serving_label ?? null,
                item.serving_quantity ?? null,
                item.calories_per_base ?? null,
                item.protein_g_per_base ?? null,
                item.carbs_g_per_base ?? null,
                item.fat_g_per_base ?? null,
                item.fiber_g_per_base ?? null,
                item.sugar_g_per_base ?? null,
                item.sodium_mg_per_base ?? null,
                Math.max(1, item.use_count ?? 1),
                item.last_used_at ?? Temporal.Now.instant().toString(),
                item.raw_json ?? null,
                item.image_path ?? null,
            );
            return repository.getById(id);
        },

        async update(id: string, updates: Partial<NewFoodItem>): Promise<FoodItem> {
            const existing = await repository.getById(id);
            log.debug('foodItems.update', { id, fields: Object.keys(updates) });

            const fields: string[] = [];
            const values: unknown[] = [];

            const allowed = [
                'canonical_name', 'display_name', 'brand', 'barcode',
                'source', 'source_ref', 'base_amount', 'base_unit', 'default_serving_amount',
                'serving_label', 'serving_quantity',
                'calories_per_base', 'protein_g_per_base', 'carbs_g_per_base', 'fat_g_per_base',
                'fiber_g_per_base', 'sugar_g_per_base', 'sodium_mg_per_base', 'raw_json',
                'image_path', 'archived_at',
            ] as const;

            for (const field of allowed) {
                if (updates[field] !== undefined) {
                    fields.push(`${field} = ?`);
                    let value = updates[field] ?? null;
                    if (field === 'canonical_name' && typeof value === 'string') {
                        value = normalizeFoodName(value);
                    }
                    values.push(value);
                }
            }

            if (fields.length === 0) return existing;

            fields.push("updated_at = datetime('now')");
            values.push(id);
            await driver.execute(`UPDATE food_items SET ${fields.join(', ')} WHERE id = ?`, ...values);
            const updated = await repository.getById(id);

            // Orphan cleanup (story 130). If image_path actually changed and the
            // OLD value is no longer referenced by any other row, fire the
            // host-supplied callback. Errors are swallowed — the row update has
            // already committed and is the primary intent.
            const oldPath = existing.image_path ?? null;
            const newPath = updated.image_path ?? null;
            if (onImageReleased && oldPath && oldPath !== newPath) {
                const stillReferenced = await isImagePathReferenced(driver, oldPath, { kind: 'food_item', id });
                if (!stillReferenced) {
                    try { await onImageReleased(oldPath); } catch { /* best-effort */ }
                }
            }
            return updated;
        },

        async markUsed(id: string): Promise<FoodItem> {
            log.debug('foodItems.markUsed', { id });
            await driver.execute(
                `
                    UPDATE food_items
                    SET use_count = use_count + 1,
                        last_used_at = datetime('now'),
                        updated_at = datetime('now')
                    WHERE id = ?
                `,
                id,
            );
            return repository.getById(id);
        },

        /**
         * Upsert by identity priority: id → barcode → source+source_ref → canonical_name+brand+source.
         * If `incrementUseCount` is set, an existing match's use_count grows by 1 and `last_used_at` ticks.
         */
        async upsert(item: NewFoodItem & { id?: string }, options?: { incrementUseCount?: boolean }): Promise<FoodItem> {
            const key = resolveUpsertKey(item);
            log.debug('foodItems.upsert', { keyKind: key.kind, source: item.source });
            const existing = await repository.findByUpsertKey(key);

            if (!existing) {
                return repository.create(item);
            }

            await repository.update(existing.id, {
                canonical_name: item.canonical_name || existing.canonical_name,
                display_name: item.display_name || existing.display_name,
                brand: item.brand ?? existing.brand,
                barcode: item.barcode ?? existing.barcode,
                source: item.source,
                source_ref: item.source_ref ?? existing.source_ref,
                base_amount: item.base_amount,
                base_unit: item.base_unit,
                default_serving_amount: item.default_serving_amount ?? existing.default_serving_amount,
                serving_label: item.serving_label ?? existing.serving_label,
                serving_quantity: item.serving_quantity ?? existing.serving_quantity,
                calories_per_base: item.calories_per_base ?? existing.calories_per_base,
                protein_g_per_base: item.protein_g_per_base ?? existing.protein_g_per_base,
                carbs_g_per_base: item.carbs_g_per_base ?? existing.carbs_g_per_base,
                fat_g_per_base: item.fat_g_per_base ?? existing.fat_g_per_base,
                fiber_g_per_base: item.fiber_g_per_base ?? existing.fiber_g_per_base,
                sugar_g_per_base: item.sugar_g_per_base ?? existing.sugar_g_per_base,
                sodium_mg_per_base: item.sodium_mg_per_base ?? existing.sodium_mg_per_base,
                raw_json: item.raw_json ?? existing.raw_json,
            });

            if (options?.incrementUseCount) {
                return repository.markUsed(existing.id);
            }
            return repository.getById(existing.id);
        },

        async findByUpsertKey(key: FoodItemUpsertKey): Promise<FoodItem | null> {
            switch (key.kind) {
                case 'id':
                    return repository.findById(key.id);
                case 'barcode':
                    return repository.findByBarcode(key.barcode);
                case 'source_ref':
                    return repository.findBySourceRef(key.source, key.source_ref);
                case 'name':
                    return driver.queryOne<FoodItem>(
                        `
                            SELECT ${FOOD_ITEM_COLUMNS} FROM food_items
                            WHERE canonical_name = ? AND COALESCE(brand, '') = COALESCE(?, '') AND source = ?
                        `,
                        [key.canonical_name, key.brand ?? null, key.source],
                    );
            }
        },

        // ──────────────────────────────────────────────────────────
        // AI estimation subtype (1-1 with food_items)
        // ──────────────────────────────────────────────────────────

        async createWithAiEstimation(item: NewFoodItem, ai: NewAiEstimation): Promise<{ foodItem: FoodItem; aiEstimation: AiEstimation }> {
            log.debug('foodItems.createWithAiEstimation', { model: ai.model_name });
            const foodItem = await repository.create({ ...item, source: 'ai_estimate' });
            await driver.execute(
                `
                    INSERT INTO ai_estimations (food_item_id, model_name, prompt_used, image_path, confidence_score, raw_response)
                    VALUES (?, ?, ?, ?, ?, ?)
                `,
                foodItem.id,
                ai.model_name,
                ai.prompt_used,
                ai.image_path ?? null,
                ai.confidence_score ?? null,
                ai.raw_response ?? null,
            );
            const aiEstimation = await driver.queryOne<AiEstimation>(
                'SELECT * FROM ai_estimations WHERE food_item_id = ?',
                [foodItem.id],
                { notFound: () => new Error(`Failed to load ai_estimation for ${foodItem.id}`) },
            );
            return { foodItem, aiEstimation };
        },

        async findAiEstimationByFoodItemId(foodItemId: string): Promise<AiEstimation | null> {
            return driver.queryOne<AiEstimation>(
                'SELECT * FROM ai_estimations WHERE food_item_id = ?',
                [foodItemId],
            );
        },

        /**
         * Create a brand-new food_items row AND log a consumption entry against it
         * in a single transaction. Used for the "log this OFF product I just
         * picked" flow: a failed save leaves nothing behind (no orphan food row).
         * If a row with the same barcode already exists, the existing one is
         * reused — the new food payload is ignored. Returns both entities.
         */
        async createAndLog(
            food: NewFoodItem,
            entry: { date: string; meal_type: MealType; amount: number },
        ): Promise<{ food_item: FoodItem; consumption_entry: ConsumptionEntry }> {
            let foodItem: FoodItem | null = null;
            if (food.barcode) {
                foodItem = await repository.findByBarcode(food.barcode);
            }

            log.debug('foodItems.createAndLog: BEGIN', { existing: !!foodItem, barcode: food.barcode ?? null });
            await driver.execute('BEGIN TRANSACTION');
            try {
                if (!foodItem) {
                    foodItem = await repository.create(food);
                }
                const macros = computeSnapshotMacros(foodItem, entry.amount);
                const entryId = await insertConsumptionEntryAndRecompute(driver, {
                    date: entry.date,
                    meal_type: entry.meal_type,
                    food_item_id: foodItem.id,
                    amount: entry.amount,
                    calories: macros.calories ?? undefined,
                    protein_g: macros.protein_g ?? undefined,
                    carbs_g: macros.carbs_g ?? undefined,
                    fat_g: macros.fat_g ?? undefined,
                    fiber_g: macros.fiber_g ?? undefined,
                    sugar_g: macros.sugar_g ?? undefined,
                    sodium_mg: macros.sodium_mg ?? undefined,
                });
                await driver.execute(
                    `UPDATE food_items SET use_count = use_count + 1, last_used_at = datetime('now'), updated_at = datetime('now') WHERE id = ?`,
                    foodItem.id,
                );
                await driver.execute('COMMIT');
                log.debug('foodItems.createAndLog: COMMIT', { foodItemId: foodItem.id, entryId });

                const consumption_entry = await driver.queryOne<ConsumptionEntry>(
                    `SELECT id, date, meal_type, food_item_id, amount,
                            calories, protein_g, carbs_g, fat_g, fiber_g, sugar_g, sodium_mg,
                            source_meal_id, meal_occurrence_id, created_at, updated_at
                     FROM consumption_entries WHERE id = ?`,
                    [entryId],
                    { notFound: () => new Error(`consumption_entry ${entryId} missing after commit`) },
                );
                const food_item = await repository.getById(foodItem.id);
                return { food_item, consumption_entry };
            } catch (err) {
                await driver.execute('ROLLBACK');
                log.warn('foodItems.createAndLog: ROLLBACK', { error: err instanceof Error ? err.message : String(err) });
                throw err;
            }
        },
    };

    return repository;
}

export type FoodItemRepository = ReturnType<typeof createFoodItemRepository>;
