// --- Health Section Types ---

export const MEAL_TYPES = ['Breakfast', 'Lunch', 'Dinner', 'Snacks'] as const;
export type MealType = typeof MEAL_TYPES[number];

/**
 * Closed set of `activities.type` values. Story 146 locks this list with a
 * `CHECK` constraint at the DB layer and at the Strava ingestion edge.
 * Manual-entry UI dropdowns iterate this array; ingestion guards against
 * Strava sport_types that snake-case to anything outside it (logged + skipped).
 *
 * `Activity.type` remains typed as `string` for read-side back-compat — the
 * CHECK constraint and ingestion guard are the runtime enforcers. Code that
 * wants to be precise (e.g. dropdown bindings, switch statements) can use the
 * derived `ActivityType` union.
 */
export const ACTIVITY_TYPES = [
    'running', 'cycling', 'walking', 'hiking', 'swimming',
    'tennis', 'ice_skate', 'alpine_ski',
    'hiit', 'weight_training', 'workout',
] as const;
export type ActivityType = typeof ACTIVITY_TYPES[number];

export type ActivitySource = 'manual' | 'strava' | 'calendar';

export interface Activity {
    id: string;
    type: string;
    source: ActivitySource;
    title: string;
    description?: string;
    date: string;
    duration_minutes?: number;
    calories_burned?: number;
    external_id?: string;
    metadata?: string;
    created_at: string;
    updated_at: string;
}

export type NewActivity = Omit<Activity, 'id' | 'created_at' | 'updated_at'>;

export type NutritionSource = 'manual' | 'openfoodfacts' | 'ai_estimate' | 'mfp_import';

export interface DailyNutritionSummary {
    date: string;
    total_calories: number;
    total_protein_g: number;
    total_carbs_g: number;
    total_fat_g: number;
    entry_count: number;
}

/**
 * Header stats for the health timeline. `streak_days` is the number of
 * consecutive days ending today (or yesterday if today has no activity yet)
 * on which the user logged at least one activity, capped at 365.
 * `avg_calories_7d` is the mean of `total_calories` across the last seven
 * days where the user actually logged consumption (zero-calorie days are
 * excluded so a single bad day doesn't drag the average to zero).
 */
export interface HealthStats {
    streak_days: number;
    avg_calories_7d: number;
}

/**
 * AI nutrition estimate. Field names align with the `food_items` table
 * (`*_per_base` against `base_amount = 100` / `base_unit = 'g'`) so the
 * server can persist the estimate without a conversion step. The model
 * also reports `default_serving_amount` (the meal's total weight in grams)
 * and a numeric `confidence_score` so AI metadata maps 1:1 onto
 * `ai_estimations.confidence_score`.
 */
export interface NutritionEstimate {
    canonical_name: string;
    display_name: string;
    base_amount: number;
    base_unit: FoodBaseUnit;
    default_serving_amount: number;
    calories_per_base: number;
    protein_g_per_base: number;
    carbs_g_per_base: number;
    fat_g_per_base: number;
    fiber_g_per_base: number;
    sugar_g_per_base: number;
    sodium_mg_per_base: number;
    confidence_score: number;
    notes: string;
}

export interface Per100gNutrition {
    calories: number;
    protein_g: number;
    carbs_g: number;
    fat_g: number;
    fiber_g?: number;
    sugar_g?: number;
    sodium_mg?: number;
}

export const FOOD_BASE_UNITS = ['g', 'ml', 'piece'] as const;
export type FoodBaseUnit = typeof FOOD_BASE_UNITS[number];

/**
 * Library entry for any loggable food. Nutrient densities are stored once
 * per row as `*_per_base` values relative to `base_amount` in `base_unit`
 * (e.g. base_amount=100 base_unit='g' for "per 100g"). The optional
 * `serving_label` + `serving_quantity` pair is a UI-only display affordance
 * — backend math always converts to grams before computing macros.
 */
export interface FoodItem {
    id: string;
    canonical_name: string;
    display_name: string;
    brand?: string;
    barcode?: string;
    source: NutritionSource;
    source_ref?: string;
    base_amount: number;
    base_unit: FoodBaseUnit;
    default_serving_amount?: number;
    serving_label?: string;
    serving_quantity?: number;
    calories_per_base?: number;
    protein_g_per_base?: number;
    carbs_g_per_base?: number;
    fat_g_per_base?: number;
    fiber_g_per_base?: number;
    sugar_g_per_base?: number;
    sodium_mg_per_base?: number;
    use_count: number;
    last_used_at: string;
    raw_json?: string;
    /**
     * Directory key under FILES_DIR/images/ (e.g. 'images/food/<uuidv7>'). The
     * UI appends `/display.jpg` (rendered, 1280px progressive JPEG) or
     * `/original.<ext>` (archive). Independent of `ai_estimations.image_path`
     * — see design_log.md #125.
     */
    image_path?: string;
    /**
     * ISO timestamp set when the row is archived. Non-NULL = hidden from
     * search/list endpoints; `GET /food-items/:id` still returns the row so
     * historical consumption_entries remain readable. Story 120.
     */
    archived_at?: string;
    created_at: string;
    updated_at: string;
}

export type NewFoodItem = Omit<FoodItem, 'id' | 'created_at' | 'updated_at' | 'last_used_at' | 'use_count'> & {
    last_used_at?: string;
    use_count?: number;
};

/**
 * 1-1 subtype of `FoodItem` for rows whose `source = 'ai_estimate'`. Holds
 * the prompt, model, image reference, and confidence so the food library
 * itself stays clean and a future RAG store can scan AI metadata directly.
 */
export interface AiEstimation {
    food_item_id: string;
    model_name: string;
    prompt_used: string;
    image_path?: string;
    confidence_score?: number;
    raw_response?: string;
    created_at: string;
}

export type NewAiEstimation = Omit<AiEstimation, 'created_at'>;

/**
 * What was actually eaten. Macros are snapshotted at log time from
 * `food_items.*_per_base × amount / base_amount`, so editing a `FoodItem`
 * later does not rewrite history. `amount` is implicitly in the referenced
 * `food_items.base_unit`. `source_meal_id` and `meal_occurrence_id` group
 * entries logged from a meal template (story 077).
 */
export interface ConsumptionEntry {
    id: string;
    date: string;
    meal_type: MealType;
    food_item_id: string;
    amount: number;
    calories?: number;
    protein_g?: number;
    carbs_g?: number;
    fat_g?: number;
    fiber_g?: number;
    sugar_g?: number;
    sodium_mg?: number;
    source_meal_id?: string;
    meal_occurrence_id?: string;
    created_at: string;
    updated_at: string;
}

export type NewConsumptionEntry = Omit<ConsumptionEntry, 'id' | 'created_at' | 'updated_at'>;

/**
 * Reusable meal template — created here so the schema is complete; behavior
 * (search integration, log-time expansion, scaling, editor UI) lives in
 * story 077.
 */
export interface Meal {
    id: string;
    name: string;
    notes?: string;
    default_scale: number;
    use_count: number;
    last_used_at?: string;
    /**
     * Directory key under FILES_DIR/images/meal/ (e.g. 'images/meal/<uuidv7>').
     * UI appends `/display.jpg`. Optional cover photo — null means no banner.
     */
    image_path?: string;
    created_at: string;
    updated_at: string;
}

export type NewMeal = Omit<Meal, 'id' | 'created_at' | 'updated_at' | 'use_count' | 'last_used_at'> & {
    use_count?: number;
    last_used_at?: string;
};

export interface MealIngredient {
    id: string;
    meal_id: string;
    food_item_id: string;
    amount: number;
    position: number;
}

export type NewMealIngredient = Omit<MealIngredient, 'id'>;

/** Ingredient row joined with its `food_items` row, returned from `meals.getById`. */
export interface MealIngredientWithFoodItem extends MealIngredient {
    food_item: FoodItem;
}

/** Meal joined with its (positionally-ordered) ingredients + each ingredient's food item. */
export interface MealWithIngredients extends Meal {
    ingredients: MealIngredientWithFoodItem[];
}

/**
 * Create / update payload for a meal template. `ingredients` is the full
 * ingredient list — the repository replaces the existing rows on update.
 * `position` is implicit (array order); the repository assigns sequential
 * indices on write.
 */
export interface NewMealWithIngredients {
    name: string;
    notes?: string;
    default_scale?: number;
    /** Optional cover-photo directory key (e.g. 'images/meal/<uuidv7>'). */
    image_path?: string;
    ingredients: Array<{ food_item_id: string; amount: number }>;
}

/** Payload for `POST /meals/:id/log` and `meals.logMeal`. */
export interface MealLogPayload {
    date: string;
    meal_type: MealType;
    /** Optional per-log scale; defaults to `meal.default_scale`. */
    scale?: number;
}

/** Result of `meals.logMeal` — the N expanded consumption entries plus their grouping id. */
export interface MealLogResult {
    meal_occurrence_id: string;
    entries: ConsumptionEntry[];
}

// --- Workout logging (story 140 / spike 138) ---

export const EXERCISE_CATEGORIES = [
    'squat', 'hinge', 'push', 'pull', 'lunge', 'core', 'olympic', 'carry', 'bodyweight', 'other',
] as const;
export type ExerciseCategory = typeof EXERCISE_CATEGORIES[number];

export const EXERCISE_DEFAULT_UNITS = ['kg', 'lb', 'bodyweight'] as const;
export type ExerciseDefaultUnit = typeof EXERCISE_DEFAULT_UNITS[number];

export const WORKOUT_BLOCK_KINDS = ['interval', 'rest', 'note'] as const;
export type WorkoutBlockKind = typeof WORKOUT_BLOCK_KINDS[number];

/**
 * Library entry for any loggable exercise (loaded barbell lift, bodyweight
 * movement, timed isometric). Analogous to `FoodItem`. `tracks_*` flags
 * disambiguate "what does logging this even mean" — `tracks_reps=0` +
 * `tracks_duration=1` describes a plank, which has no reps and no weight.
 */
export interface Exercise {
    id: string;
    canonical_name: string;
    display_name: string;
    category: ExerciseCategory;
    default_unit: ExerciseDefaultUnit;
    tracks_reps: number;
    tracks_weight: number;
    tracks_duration: number;
    notes?: string;
    use_count: number;
    last_used_at?: string;
    archived_at?: string;
    created_at: string;
    updated_at: string;
}

export type NewExercise = Omit<Exercise, 'id' | 'created_at' | 'updated_at' | 'use_count' | 'last_used_at'> & {
    use_count?: number;
    last_used_at?: string;
};

/**
 * 1:1 optional subtype of `activities` carrying Strava session-level metrics.
 * A row exists when Strava (or manual entry) supplied at least one measured
 * metric. Individual columns are nullable — NULL means "not measured," never
 * "measured as zero." Spike 138 §4.2.
 */
export interface CardioDetails {
    activity_id: string;
    distance_m?: number;
    elevation_gain_m?: number;
    avg_speed_mps?: number;
    avg_hr?: number;
    max_hr?: number;
    gear_name?: string;
    strava_sport_type?: string;
    created_at: string;
    updated_at: string;
}

export type NewCardioDetails = Omit<CardioDetails, 'created_at' | 'updated_at'>;

/**
 * 1:1 optional subtype of `activities` carrying intra-session structure
 * (strength sets and/or interval blocks). `activity_id` is both PK and FK —
 * same pattern as `ai_estimations.food_item_id`. Spike 138 §4.3.
 */
export interface WorkoutSession {
    activity_id: string;
    source_template_id?: string;
    notes?: string;
    created_at: string;
    updated_at: string;
}

export type NewWorkoutSession = Omit<WorkoutSession, 'created_at' | 'updated_at'>;

/**
 * One row per actual set performed. `position` is the global order within the
 * session (squat1, squat2, …, bench1, bench2); `set_index` is the 1..N within
 * the same exercise (squat is 1-3, bench is 1-2). Spike 138 §4.4.
 */
export interface StrengthSet {
    id: string;
    session_id: string;
    position: number;
    exercise_id: string;
    set_index: number;
    reps?: number;
    weight_kg?: number;
    rpe?: number;
    rest_s?: number;
    notes?: string;
}

export type NewStrengthSet = Omit<StrengthSet, 'id'>;

/**
 * Intervals / rest / notes attached to a workout session. Flat — no recursive
 * `parent_block_id`. The TRIB3 "5 min run → 1 min speed 6 / 1 min speed 7"
 * case becomes sibling rows sharing `parent_label='5 min run'`. Spike 138 §4.5.
 */
export interface WorkoutBlock {
    id: string;
    session_id: string;
    position: number;
    parent_label?: string;
    kind: WorkoutBlockKind;
    modality?: string;
    duration_s?: number;
    distance_m?: number;
    intensity?: string;
    avg_hr?: number;
    notes?: string;
}

export type NewWorkoutBlock = Omit<WorkoutBlock, 'id'>;

/** Session joined with its strength sets and workout blocks — the read shape returned by `workouts.getById`. */
export interface WorkoutSessionWithDetail extends WorkoutSession {
    strength_sets: StrengthSet[];
    workout_blocks: WorkoutBlock[];
}

/**
 * Reusable workout prescription. Logging a template expands it into a session
 * in one transaction (mirrors `meals.logMeal`, design_log #117). Editing the
 * template never rewrites history. Spike 138 §4.6.
 */
export interface WorkoutTemplate {
    id: string;
    name: string;
    notes?: string;
    use_count: number;
    last_used_at?: string;
    archived_at?: string;
    created_at: string;
    updated_at: string;
}

export type NewWorkoutTemplate = Omit<WorkoutTemplate, 'id' | 'created_at' | 'updated_at' | 'use_count' | 'last_used_at'> & {
    use_count?: number;
    last_used_at?: string;
};

export interface TemplateStrengthSet {
    id: string;
    template_id: string;
    position: number;
    exercise_id: string;
    target_set_count: number;
    target_reps?: number;
    target_weight_kg?: number;
    target_rpe?: number;
    target_rest_s?: number;
    notes?: string;
}

export type NewTemplateStrengthSet = Omit<TemplateStrengthSet, 'id'>;

export interface TemplateBlock {
    id: string;
    template_id: string;
    position: number;
    parent_label?: string;
    kind: WorkoutBlockKind;
    modality?: string;
    target_duration_s?: number;
    target_distance_m?: number;
    target_intensity?: string;
    notes?: string;
}

export type NewTemplateBlock = Omit<TemplateBlock, 'id'>;

/** Template joined with its (positionally-ordered) target sets and blocks. */
export interface WorkoutTemplateWithBlocks extends WorkoutTemplate {
    strength_sets: TemplateStrengthSet[];
    blocks: TemplateBlock[];
}

/**
 * Create/update payload for a workout template. `strength_sets` and `blocks` are
 * the full positional child lists — the repository replaces existing rows on
 * update (same pattern as meal_ingredients).
 */
export interface NewWorkoutTemplateWithBlocks {
    name: string;
    notes?: string;
    strength_sets: Array<Omit<NewTemplateStrengthSet, 'template_id' | 'position'>>;
    blocks?: Array<Omit<NewTemplateBlock, 'template_id' | 'position'>>;
}

/** Payload for `workouts.logTemplate(template_id, payload)`. */
export interface WorkoutLogPayload {
    date: string;
    title?: string;
}

/** Result of `workouts.logTemplate` — the created activity id and the populated session. */
export interface WorkoutLogResult {
    activity_id: string;
    session: WorkoutSessionWithDetail;
}
