    // --- Workout templates ---

    private validateTemplateChildren(payload: Partial<NewWorkoutTemplateWithBlocks>, { requireChildren }: { requireChildren: boolean }): ApiResponse | null {
        const sets = payload.strength_sets;
        const blocks = payload.blocks;
        if (sets !== undefined) {
            if (!Array.isArray(sets)) return this.badRequest('strength_sets must be an array');
            for (const [i, s] of sets.entries()) {
                if (!s || typeof s !== 'object') return this.badRequest(`strength_sets[${i}] must be an object`);
                if (!s.exercise_id || typeof s.exercise_id !== 'string') return this.badRequest(`strength_sets[${i}].exercise_id is required`);
                if (typeof s.target_set_count !== 'number' || !Number.isInteger(s.target_set_count) || s.target_set_count <= 0) {
                    return this.badRequest(`strength_sets[${i}].target_set_count must be a positive integer`);
                }
            }
        }
        if (blocks !== undefined) {
            if (!Array.isArray(blocks)) return this.badRequest('blocks must be an array');
            for (const [i, blk] of blocks.entries()) {
                if (!blk || typeof blk !== 'object') return this.badRequest(`blocks[${i}] must be an object`);
                if (!blk.kind || !WORKOUT_BLOCK_KINDS.includes(blk.kind as WorkoutBlockKind)) {
                    return this.badRequest(`blocks[${i}].kind must be one of: ${WORKOUT_BLOCK_KINDS.join(', ')}`);
                }
            }
        }
        if (requireChildren) {
            const hasSets = (sets?.length ?? 0) > 0;
            const hasBlocks = (blocks?.length ?? 0) > 0;
            if (!hasSets && !hasBlocks) return this.badRequest('Template must have at least one strength set or block');
        }
        return null;
    }

