    // --- Strength sets ---

    private validateStrengthSetPayload(b: Partial<NewStrengthSet>, { requireExercise }: { requireExercise: boolean }): ApiResponse | null {
        if (requireExercise) {
            if (!b.exercise_id || typeof b.exercise_id !== 'string') return this.badRequest('exercise_id is required');
        }
        for (const k of ['reps', 'set_index', 'position', 'rest_s'] as const) {
            if (b[k] !== undefined && (typeof b[k] !== 'number' || !Number.isInteger(b[k]) || (b[k] as number) < 0)) {
                return this.badRequest(`${k} must be a non-negative integer`);
            }
        }
        for (const k of ['weight_kg', 'rpe'] as const) {
            if (b[k] !== undefined && b[k] !== null && (typeof b[k] !== 'number' || !Number.isFinite(b[k]) || (b[k] as number) < 0)) {
                return this.badRequest(`${k} must be a non-negative number`);
            }
        }
        return null;
    }

