import { AbstractRouteResponses, type ApiResponse, type RouteContext } from './response-helpers.js';
import type {
    ProjectDashboardData,
    ProjectGitLogResponse,
    ProjectStoriesResponse,
    ProjectSummaryData,
} from '../types/projects.js';
import type {
    ClientLogDevicesResponse,
    ClientLogsQuery,
    LogLevel,
    LogsQuery,
    LogsResponse,
} from '../types/logs.js';
import type {
    CreateStoryBody,
    CreateStoryResponse,
    PatchScrumboardBody,
    PatchStoryBody,
    ScrumboardBacklogLaneId,
    ScrumboardLaneId,
    ScrumboardLaneMove,
    ScrumboardResponse,
    StoryDraftRequestBody,
    StoryDraftResponse,
    StoryResponse,
    StorySectionKey,
} from '../types/projects-story.js';
import { STORY_SECTION_KEYS } from '../types/projects-story.js';

const STORY_ID_RE = /^\d{3}[a-z]?$/;
const SCRUMBOARD_LANE_IDS: ReadonlyArray<ScrumboardLaneId> = [
    'active-sprint',
    'completed',
    'high-priority',
    'medium-priority',
    'low-priority',
    'superseded',
];
const BACKLOG_LANE_IDS: ReadonlyArray<ScrumboardBacklogLaneId> = [
    'high-priority',
    'medium-priority',
    'low-priority',
    'superseded',
];

const UUIDV7_RE = /^[0-9a-f]{8}-[0-9a-f]{4}-7[0-9a-f]{3}-[89ab][0-9a-f]{3}-[0-9a-f]{12}$/i;
const PLAIN_DATE_RE = /^\d{4}-\d{2}-\d{2}$/;

function isPlainDateString(value: string): boolean {
    if (!PLAIN_DATE_RE.test(value)) return false;
    try {
        return Temporal.PlainDate.from(value).toString() === value;
    } catch {
        return false;
    }
}

export type ProjectsRouteKey =
    | 'GET /status'
    | 'GET /motivation'
    | 'GET /motivation/summary'
    | 'GET /motivation/stories'
    | 'GET /motivation/git-log'
    | 'GET /motivation/logs'
    | 'GET /motivation/client-logs'
    | 'GET /motivation/client-logs/devices'
    | 'GET /motivation/scrumboard'
    | 'PATCH /motivation/scrumboard'
    | 'GET /motivation/stories/:id'
    | 'POST /motivation/stories'
    | 'PATCH /motivation/stories/:id'
    | 'POST /motivation/stories/draft-from-notes';

export const PROJECTS_ROUTE_KEYS: readonly ProjectsRouteKey[] = [
    'GET /status',
    'GET /motivation',
    'GET /motivation/summary',
    'GET /motivation/stories',
    'GET /motivation/git-log',
    'GET /motivation/logs',
    'GET /motivation/client-logs',
    'GET /motivation/client-logs/devices',
    'GET /motivation/scrumboard',
    'PATCH /motivation/scrumboard',
    'GET /motivation/stories/:id',
    'POST /motivation/stories',
    'PATCH /motivation/stories/:id',
    'POST /motivation/stories/draft-from-notes',
] as const;

export interface IProjectsRoutes {
    'GET /status'(ctx: RouteContext): Promise<ApiResponse>;
    'GET /motivation'(ctx: RouteContext): Promise<ApiResponse>;
    'GET /motivation/summary'(ctx: RouteContext): Promise<ApiResponse>;
    'GET /motivation/stories'(ctx: RouteContext): Promise<ApiResponse>;
    'GET /motivation/git-log'(ctx: RouteContext): Promise<ApiResponse>;
    'GET /motivation/logs'(ctx: RouteContext): Promise<ApiResponse>;
    'GET /motivation/client-logs'(ctx: RouteContext): Promise<ApiResponse>;
    'GET /motivation/client-logs/devices'(ctx: RouteContext): Promise<ApiResponse>;
    'GET /motivation/scrumboard'(ctx: RouteContext): Promise<ApiResponse>;
    'PATCH /motivation/scrumboard'(ctx: RouteContext): Promise<ApiResponse>;
    'GET /motivation/stories/:id'(ctx: RouteContext): Promise<ApiResponse>;
    'POST /motivation/stories'(ctx: RouteContext): Promise<ApiResponse>;
    'PATCH /motivation/stories/:id'(ctx: RouteContext): Promise<ApiResponse>;
    'POST /motivation/stories/draft-from-notes'(ctx: RouteContext): Promise<ApiResponse>;
}

export interface ProjectsRepository {
    getMotivationDashboard(): Promise<ProjectDashboardData>;
    getMotivationSummary(): Promise<ProjectSummaryData>;
    getMotivationStories(): Promise<ProjectStoriesResponse>;
    getMotivationGitLog(): Promise<ProjectGitLogResponse>;
    getLogEntries(query: LogsQuery): Promise<LogsResponse>;
    getClientLogEntries(query: ClientLogsQuery): Promise<LogsResponse>;
    getClientLogDevices(): Promise<ClientLogDevicesResponse>;
    getScrumboard(): Promise<ScrumboardResponse>;
    patchScrumboard(body: PatchScrumboardBody): Promise<ScrumboardResponse>;
    getStoryById(id: string): Promise<StoryResponse>;
    createStory(body: CreateStoryBody): Promise<CreateStoryResponse>;
    patchStory(id: string, body: PatchStoryBody): Promise<StoryResponse>;
    draftStoryFromNotes(notes: string): Promise<StoryDraftResponse>;
}

export abstract class AbstractProjectsRoutes extends AbstractRouteResponses implements IProjectsRoutes {
    protected abstract readonly repo: ProjectsRepository;

    async 'GET /status'(): Promise<ApiResponse> {
        return this.ok({
            section: 'projects',
            status: 'operational',
            features: ['scrumboard', 'git-activity', 'server-control'],
        });
    }

    async 'GET /motivation'(): Promise<ApiResponse> {
        return this.ok(await this.repo.getMotivationDashboard());
    }

    async 'GET /motivation/summary'(): Promise<ApiResponse> {
        return this.ok(await this.repo.getMotivationSummary());
    }

    async 'GET /motivation/stories'(): Promise<ApiResponse> {
        return this.ok(await this.repo.getMotivationStories());
    }

    async 'GET /motivation/git-log'(): Promise<ApiResponse> {
        return this.ok(await this.repo.getMotivationGitLog());
    }

    async 'GET /motivation/logs'({ query }: RouteContext): Promise<ApiResponse> {
        const date = query.get('date') ??    undefined;
        const levelStr = query.get('level');
        const level = levelStr ? levelStr.split(',') as LogLevel[] : undefined;
        const search = query.get('search') ?? undefined;
        const limitStr = query.get('limit');
        const limit = limitStr ? parseInt(limitStr, 10) : undefined;
        const offsetStr = query.get('offset');
        const offset = offsetStr ? parseInt(offsetStr, 10) : undefined;

        const q: LogsQuery = {
            date,
            level,
            search,
            limit,
            offset,
        };

        return this.ok(await this.repo.getLogEntries(q));
    }

    async 'GET /motivation/client-logs'({ query }: RouteContext): Promise<ApiResponse> {
        const deviceId = query.get('device') ?? '';
        if (!deviceId) {
            return this.badRequest('device query param is required');
        }
        if (!UUIDV7_RE.test(deviceId)) {
            return this.badRequest('device query param must be a UUIDv7 string');
        }
        const date = query.get('date') ?? undefined;
        if (date !== undefined && !isPlainDateString(date)) {
            return this.badRequest('date query param must be a YYYY-MM-DD plain date');
        }
        const levelStr = query.get('level');
        const level = levelStr ? (levelStr.split(',') as LogLevel[]) : undefined;
        const search = query.get('search') ?? undefined;
        const limitStr = query.get('limit');
        const limit = limitStr ? parseInt(limitStr, 10) : undefined;
        const offsetStr = query.get('offset');
        const offset = offsetStr ? parseInt(offsetStr, 10) : undefined;

        const q: ClientLogsQuery = {
            device_id: deviceId,
            date,
            level,
            search,
            limit,
            offset,
        };

        return this.ok(await this.repo.getClientLogEntries(q));
    }

    async 'GET /motivation/client-logs/devices'(): Promise<ApiResponse> {
        return this.ok(await this.repo.getClientLogDevices());
    }

    async 'GET /motivation/scrumboard'(): Promise<ApiResponse> {
        return this.ok(await this.repo.getScrumboard());
    }

    async 'PATCH /motivation/scrumboard'({ body }: RouteContext): Promise<ApiResponse> {
        const validated = validatePatchScrumboardBody(body);
        if ('error' in validated) return this.badRequest(validated.error);
        return this.ok(await this.repo.patchScrumboard(validated.body));
    }

    async 'GET /motivation/stories/:id'({ params }: RouteContext): Promise<ApiResponse> {
        if (!STORY_ID_RE.test(params.id ?? '')) {
            return this.badRequest('Story id must match /^\\d{3}[a-z]?$/');
        }
        return this.ok(await this.repo.getStoryById(params.id));
    }

    async 'POST /motivation/stories'({ body }: RouteContext): Promise<ApiResponse> {
        const validated = validateCreateStoryBody(body);
        if ('error' in validated) return this.badRequest(validated.error);
        return this.created(await this.repo.createStory(validated.body));
    }

    async 'PATCH /motivation/stories/:id'({ params, body }: RouteContext): Promise<ApiResponse> {
        if (!STORY_ID_RE.test(params.id ?? '')) {
            return this.badRequest('Story id must match /^\\d{3}[a-z]?$/');
        }
        const validated = validatePatchStoryBody(body);
        if ('error' in validated) return this.badRequest(validated.error);
        return this.ok(await this.repo.patchStory(params.id, validated.body));
    }

    async 'POST /motivation/stories/draft-from-notes'({ body }: RouteContext): Promise<ApiResponse> {
        const validated = validateStoryDraftRequestBody(body);
        if ('error' in validated) return this.badRequest(validated.error);
        return this.ok(await this.repo.draftStoryFromNotes(validated.body.notes));
    }
}

function validateStoryDraftRequestBody(body: unknown): { body: StoryDraftRequestBody } | { error: string } {
    const b = (body ?? {}) as Record<string, unknown>;
    if (typeof b.notes !== 'string') return { error: 'notes must be a string' };
    const trimmed = b.notes.trim();
    if (trimmed.length === 0) return { error: 'notes must be non-empty' };
    if (b.notes.length > 16 * 1024) return { error: 'notes must be 16KB or fewer' };
    return { body: { notes: b.notes } };
}

const SECTION_VALUE_MAX_LENGTH = 8 * 1024;
const CONTROL_CHAR_RE = /[\x00-\x08\x0b\x0c\x0e-\x1f\x7f]/;

/**
 * Validate a candidate `StoryDraft` from an untrusted source (the AI structuring endpoint).
 * Per-field length caps, valid section keys only, no control characters or NULs. Returns
 * `{ draft }` on success, `{ error }` describing the first failure.
 *
 * Shared between the route validator (for the unlikely case the PWA ever POSTs a pre-built
 * draft) and `ollamaService.draftStoryFromNotes`, which runs this on the LLM's parsed JSON.
 */
export function validateStoryDraft(input: unknown): { draft: import('../types/projects-story.js').StoryDraft } | { error: string } {
    if (typeof input !== 'object' || input === null || Array.isArray(input)) {
        return { error: 'draft must be an object' };
    }
    const draft = input as Record<string, unknown>;
    if (typeof draft.title !== 'string' || draft.title.trim().length === 0) {
        return { error: 'draft.title is required and must be a non-empty string' };
    }
    if (draft.title.length > 200) return { error: 'draft.title must be 200 characters or fewer' };
    if (CONTROL_CHAR_RE.test(draft.title)) return { error: 'draft.title contains a forbidden control character' };

    const sections: Partial<Record<StorySectionKey, string>> = {};
    if (draft.sections !== undefined) {
        if (typeof draft.sections !== 'object' || draft.sections === null || Array.isArray(draft.sections)) {
            return { error: 'draft.sections must be an object' };
        }
        for (const [key, value] of Object.entries(draft.sections)) {
            if (!STORY_SECTION_KEYS.includes(key as StorySectionKey)) {
                return { error: `draft.sections has unknown key: ${key}` };
            }
            if (typeof value !== 'string') return { error: `draft.sections.${key} must be a string` };
            if (value.length > SECTION_VALUE_MAX_LENGTH) {
                return { error: `draft.sections.${key} exceeds ${SECTION_VALUE_MAX_LENGTH} characters` };
            }
            if (CONTROL_CHAR_RE.test(value)) {
                return { error: `draft.sections.${key} contains a forbidden control character` };
            }
            sections[key as StorySectionKey] = value;
        }
    }

    return { draft: { title: draft.title.trim(), sections } };
}

function validatePatchScrumboardBody(body: unknown): { body: PatchScrumboardBody } | { error: string } {
    const b = (body ?? {}) as Record<string, unknown>;
    const result: PatchScrumboardBody = {};
    if (b.sprintName !== undefined) {
        if (typeof b.sprintName !== 'string') return { error: 'sprintName must be a string' };
        result.sprintName = b.sprintName;
    }
    if (b.sprintGoal !== undefined) {
        if (typeof b.sprintGoal !== 'string') return { error: 'sprintGoal must be a string' };
        result.sprintGoal = b.sprintGoal;
    }
    if (b.moves !== undefined) {
        if (!Array.isArray(b.moves)) return { error: 'moves must be an array' };
        const moves: ScrumboardLaneMove[] = [];
        for (const raw of b.moves) {
            const r = (raw ?? {}) as Record<string, unknown>;
            if (typeof r.id !== 'string' || r.id.length === 0) return { error: 'each move requires a non-empty id' };
            if (!isLaneId(r.fromLane)) return { error: `each move requires a valid fromLane (got ${String(r.fromLane)})` };
            if (!isLaneId(r.toLane)) return { error: `each move requires a valid toLane (got ${String(r.toLane)})` };
            const move: ScrumboardLaneMove = { id: r.id, fromLane: r.fromLane, toLane: r.toLane };
            if (r.position !== undefined) {
                if (typeof r.position !== 'number' || !Number.isInteger(r.position) || r.position < 0) {
                    return { error: 'position must be a non-negative integer' };
                }
                move.position = r.position;
            }
            moves.push(move);
        }
        result.moves = moves;
    }
    return { body: result };
}

function validateCreateStoryBody(body: unknown): { body: CreateStoryBody } | { error: string } {
    const b = (body ?? {}) as Record<string, unknown>;
    if (typeof b.title !== 'string' || b.title.trim().length === 0) {
        return { error: 'title is required' };
    }
    if (b.title.length > 200) {
        return { error: 'title must be 200 characters or fewer' };
    }
    const result: CreateStoryBody = { title: b.title.trim() };
    if (b.sections !== undefined) {
        const sections = validateSections(b.sections);
        if ('error' in sections) return sections;
        result.sections = sections.sections;
    }
    if (b.backlogLane !== undefined) {
        if (typeof b.backlogLane !== 'string' || !BACKLOG_LANE_IDS.includes(b.backlogLane as ScrumboardBacklogLaneId)) {
            return { error: 'backlogLane must be one of high-priority|medium-priority|low-priority|superseded' };
        }
        result.backlogLane = b.backlogLane as ScrumboardBacklogLaneId;
    }
    return { body: result };
}

function validatePatchStoryBody(body: unknown): { body: PatchStoryBody } | { error: string } {
    const b = (body ?? {}) as Record<string, unknown>;
    const result: PatchStoryBody = {};
    if (b.title !== undefined) {
        if (typeof b.title !== 'string' || b.title.trim().length === 0) return { error: 'title must be non-empty' };
        if (b.title.length > 200) return { error: 'title must be 200 characters or fewer' };
        result.title = b.title.trim();
    }
    if (b.sections !== undefined) {
        const sections = validateSections(b.sections);
        if ('error' in sections) return sections;
        result.sections = sections.sections;
    }
    return { body: result };
}

function validateSections(input: unknown): { sections: Partial<Record<StorySectionKey, string>> } | { error: string } {
    if (typeof input !== 'object' || input === null || Array.isArray(input)) {
        return { error: 'sections must be an object' };
    }
    const sections: Partial<Record<StorySectionKey, string>> = {};
    for (const [key, value] of Object.entries(input)) {
        if (!STORY_SECTION_KEYS.includes(key as StorySectionKey)) {
            return { error: `unknown section key: ${key}` };
        }
        if (typeof value !== 'string') return { error: `section ${key} must be a string` };
        sections[key as StorySectionKey] = value;
    }
    return { sections };
}

function isLaneId(value: unknown): value is ScrumboardLaneId {
    return typeof value === 'string' && SCRUMBOARD_LANE_IDS.includes(value as ScrumboardLaneId);
}
