import type { Activity, NewActivity } from '../index.js';
import type { DbDriver } from '../types/db.js';
import { NOOP_LOGGER, type RepoLogger } from '../types/logger.js';
import { uuidv7 } from '../utils/uuid.js';
import { NotFoundError } from '../api/response-helpers.js';

export interface HealthRepositoryOptions {
    log?: RepoLogger;
}

export function createHealthRepository(driver: DbDriver, options: HealthRepositoryOptions = {}) {
    const log = options.log ?? NOOP_LOGGER;
    const repository = {
        async getAllActivities(limit = 50): Promise<Activity[]> {
            log.debug('health.getAllActivities', { limit });
            return driver.query<Activity>('SELECT * FROM activities ORDER BY date DESC LIMIT ?', limit);
        },

        async findActivityById(id: string): Promise<Activity | null> {
            log.debug('health.findActivityById', { id });
            return driver.queryOne<Activity>('SELECT * FROM activities WHERE id = ?', [id]);
        },

        async getActivityById(id: string): Promise<Activity> {
            log.debug('health.getActivityById', { id });
            return driver.queryOne<Activity>('SELECT * FROM activities WHERE id = ?', [id], {
                notFound: () => new NotFoundError(`Activity ${id} not found`),
            });
        },

        async getActivitiesByDateRange(from: string, to: string): Promise<Activity[]> {
            log.debug('health.getActivitiesByDateRange', { from, to });
            return driver.query<Activity>('SELECT * FROM activities WHERE date >= ? AND date <= ? ORDER BY date DESC', from, to);
        },

        async getActivitiesByDate(date: string): Promise<Activity[]> {
            log.debug('health.getActivitiesByDate', { date });
            return driver.query<Activity>('SELECT * FROM activities WHERE date = ? ORDER BY date DESC', date);
        },

        async getActivityDatesDescSince(sinceDate: string): Promise<string[]> {
            log.debug('health.getActivityDatesDescSince', { sinceDate });
            const rows = await driver.query<{ date: string }>(
                'SELECT DISTINCT date FROM activities WHERE date >= ? ORDER BY date DESC',
                sinceDate,
            );
            return rows.map((row) => row.date);
        },

        async findActivityByExternalId(externalId: string): Promise<Activity | null> {
            log.debug('health.findActivityByExternalId', { externalId });
            return driver.queryOne<Activity>('SELECT * FROM activities WHERE external_id = ?', [externalId]);
        },

        async createActivity(activity: NewActivity): Promise<Activity> {
            const id = uuidv7();
            log.debug('health.createActivity', { id, type: activity.type, source: activity.source });
            await driver.execute(
                `
                    INSERT INTO activities (id, type, source, title, description, date, duration_minutes, calories_burned, external_id, metadata)
                    VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
                `,
                id,
                activity.type,
                activity.source,
                activity.title,
                activity.description ?? null,
                activity.date,
                activity.duration_minutes ?? null,
                activity.calories_burned ?? null,
                activity.external_id ?? null,
                activity.metadata ?? null,
            );
            return driver.queryOne<Activity>('SELECT * FROM activities WHERE id = ?', [id], {
                notFound: () => new Error(`Failed to load created activity: ${id}`),
            });
        },

        async updateActivity(id: string, updates: Partial<NewActivity>): Promise<Activity> {
            const existing = await repository.getActivityById(id);
            log.debug('health.updateActivity', { id, fields: Object.keys(updates) });

            const fields: string[] = [];
            const values: unknown[] = [];

            const allowedFields = ['type', 'title', 'description', 'date', 'duration_minutes', 'calories_burned'] as const;
            for (const field of allowedFields) {
                if (updates[field] !== undefined) {
                    fields.push(`${field} = ?`);
                    values.push(updates[field] ?? null);
                }
            }

            if (fields.length === 0) return existing;

            values.push(id);
            await driver.execute(`UPDATE activities SET ${fields.join(', ')} WHERE id = ?`, ...values);
            return repository.getActivityById(id);
        },

        async deleteActivity(id: string): Promise<boolean> {
            log.debug('health.deleteActivity', { id });
            const result = await driver.execute('DELETE FROM activities WHERE id = ?', id);
            return result.changes > 0;
        },
    };

    return repository;
}

export type HealthRepository = ReturnType<typeof createHealthRepository>;
