import type {
    FoodItem,
    Meal,
    MealIngredient,
    MealIngredientWithFoodItem,
    MealLogPayload,
    MealLogResult,
    MealWithIngredients,
    NewMealWithIngredients,
} from '../types/health.js';
import type { ConsumptionEntry } from '../types/health.js';
import type { DbDriver } from '../types/db.js';
import { NOOP_LOGGER, type RepoLogger } from '../types/logger.js';
import { uuidv7 } from '../utils/uuid.js';
import { NotFoundError } from '../api/response-helpers.js';
import { computeSnapshotMacros, insertConsumptionEntryAndRecompute } from './consumption-entries.repository.js';
import { isImagePathReferenced } from './image-references.js';

const MEAL_COLUMNS = `id, name, notes, default_scale, use_count, last_used_at, image_path, created_at, updated_at`;
const FOOD_ITEM_COLUMNS = `
    id, canonical_name, display_name, brand, barcode,
    source, source_ref, base_amount, base_unit, default_serving_amount,
    serving_label, serving_quantity,
    calories_per_base, protein_g_per_base, carbs_g_per_base, fat_g_per_base,
    fiber_g_per_base, sugar_g_per_base, sodium_mg_per_base,
    use_count, last_used_at, raw_json, created_at, updated_at
`;

function normalizeName(value: string): string {
    return value.trim().toLowerCase().replace(/\s+/g, ' ');
}

async function loadIngredients(driver: DbDriver, mealId: string): Promise<MealIngredientWithFoodItem[]> {
    const ingredients = await driver.query<MealIngredient>(
        `SELECT id, meal_id, food_item_id, amount, position
         FROM meal_ingredients
         WHERE meal_id = ?
         ORDER BY position ASC`,
        mealId,
    );
    if (ingredients.length === 0) return [];

    const placeholders = ingredients.map(() => '?').join(',');
    const foodItems = await driver.query<FoodItem>(
        `SELECT ${FOOD_ITEM_COLUMNS} FROM food_items WHERE id IN (${placeholders})`,
        ...ingredients.map((i) => i.food_item_id),
    );
    const foodById = new Map(foodItems.map((f) => [f.id, f]));

    return ingredients.map((ing) => {
        const food = foodById.get(ing.food_item_id);
        if (!food) throw new Error(`Food item ${ing.food_item_id} missing for meal ingredient ${ing.id}`);
        return { ...ing, food_item: food };
    });
}

async function insertIngredients(
    driver: DbDriver,
    mealId: string,
    items: NewMealWithIngredients['ingredients'],
): Promise<void> {
    for (const [index, ing] of items.entries()) {
        await driver.execute(
            `INSERT INTO meal_ingredients (id, meal_id, food_item_id, amount, position) VALUES (?, ?, ?, ?, ?)`,
            uuidv7(),
            mealId,
            ing.food_item_id,
            ing.amount,
            index,
        );
    }
}

/**
 * Optional host callbacks. Story 130. The server wires `onImageReleased` to
 * delete the on-disk directory; the PWA leaves it unset.
 */
export interface MealRepositoryOptions {
    log?: RepoLogger;
    /**
     * Fired after a meal row's `image_path` changes or the row is deleted,
     * once the old path is confirmed unreferenced. Best-effort — errors are
     * caught and swallowed.
     */
    onImageReleased?: (imagePath: string) => Promise<void> | void;
}

export function createMealRepository(driver: DbDriver, options: MealRepositoryOptions = {}) {
    const log = options.log ?? NOOP_LOGGER;
    const onImageReleased = options.onImageReleased;
    const repository = {
        async findById(id: string): Promise<MealWithIngredients | null> {
            log.debug('meals.findById', { id });
            const meal = await driver.queryOne<Meal>(`SELECT ${MEAL_COLUMNS} FROM meals WHERE id = ?`, [id]);
            if (!meal) return null;
            const ingredients = await loadIngredients(driver, meal.id);
            return { ...meal, ingredients };
        },

        async getById(id: string): Promise<MealWithIngredients> {
            log.debug('meals.getById', { id });
            const meal = await driver.queryOne<Meal>(`SELECT ${MEAL_COLUMNS} FROM meals WHERE id = ?`, [id], {
                notFound: () => new NotFoundError(`Meal ${id} not found`),
            });
            const ingredients = await loadIngredients(driver, meal.id);
            return { ...meal, ingredients };
        },

        async list({ limit = 50 }: { limit?: number } = {}): Promise<Meal[]> {
            log.debug('meals.list', { limit });
            return driver.query<Meal>(
                `SELECT ${MEAL_COLUMNS} FROM meals ORDER BY use_count DESC, last_used_at DESC, name ASC LIMIT ?`,
                limit,
            );
        },

        async search(query: string, limit = 10): Promise<Meal[]> {
            log.debug('meals.search', { query, limit });
            const normalized = normalizeName(query);
            if (!normalized) return repository.list({ limit });
            return driver.query<Meal>(
                `
                    SELECT ${MEAL_COLUMNS},
                           CASE
                                WHEN LOWER(name) = ? THEN 0
                                WHEN LOWER(name) LIKE ? THEN 1
                                WHEN LOWER(name) LIKE ? THEN 2
                                ELSE 3
                           END AS rank
                    FROM meals
                    WHERE LOWER(name) LIKE ?
                    ORDER BY rank ASC, use_count DESC, last_used_at DESC, name ASC
                    LIMIT ?
                `,
                normalized,
                `${normalized}%`,
                `% ${normalized}%`,
                `%${normalized}%`,
                limit,
            );
        },

        async create(payload: NewMealWithIngredients): Promise<MealWithIngredients> {
            if (!payload.name || !payload.name.trim()) throw new Error('Meal name is required');
            if (!payload.ingredients?.length) throw new Error('Meal must have at least one ingredient');

            const id = uuidv7();
            const defaultScale = payload.default_scale ?? 1.0;

            log.debug('meals.create: BEGIN', { id, ingredientCount: payload.ingredients.length });
            await driver.execute('BEGIN TRANSACTION');
            try {
                await driver.execute(
                    `INSERT INTO meals (id, name, notes, default_scale, image_path) VALUES (?, ?, ?, ?, ?)`,
                    id,
                    payload.name.trim(),
                    payload.notes ?? null,
                    defaultScale,
                    payload.image_path ?? null,
                );
                await insertIngredients(driver, id, payload.ingredients);
                await driver.execute('COMMIT');
                log.debug('meals.create: COMMIT', { id });
            } catch (err) {
                await driver.execute('ROLLBACK');
                log.warn('meals.create: ROLLBACK', { id, error: err instanceof Error ? err.message : String(err) });
                throw err;
            }
            return repository.getById(id);
        },

        async update(
            id: string,
            updates: Partial<NewMealWithIngredients>,
        ): Promise<MealWithIngredients> {
            const existing = await repository.getById(id);
            log.debug('meals.update: BEGIN', { id, fields: Object.keys(updates) });

            // Validate before opening the transaction so a bad payload fails fast.
            if (updates.name !== undefined && !updates.name.trim()) {
                throw new Error('Meal name is required');
            }
            if (updates.ingredients !== undefined && !updates.ingredients.length) {
                throw new Error('Meal must have at least one ingredient');
            }

            await driver.execute('BEGIN TRANSACTION');
            try {
                const fields: string[] = [];
                const values: unknown[] = [];
                const allowed = ['name', 'notes', 'default_scale', 'image_path'] as const;
                for (const field of allowed) {
                    if (updates[field] !== undefined) {
                        fields.push(`${field} = ?`);
                        const value = updates[field] ?? null;
                        values.push(field === 'name' && typeof value === 'string' ? value.trim() : value);
                    }
                }
                if (fields.length > 0) {
                    fields.push("updated_at = datetime('now')");
                    values.push(id);
                    await driver.execute(`UPDATE meals SET ${fields.join(', ')} WHERE id = ?`, ...values);
                }

                if (updates.ingredients) {
                    await driver.execute('DELETE FROM meal_ingredients WHERE meal_id = ?', id);
                    await insertIngredients(driver, id, updates.ingredients);
                }
                await driver.execute('COMMIT');
                log.debug('meals.update: COMMIT', { id });
            } catch (err) {
                await driver.execute('ROLLBACK');
                log.warn('meals.update: ROLLBACK', { id, error: err instanceof Error ? err.message : String(err) });
                throw err;
            }
            const updated = await repository.getById(id);

            // Orphan cleanup (story 130). Same shape as the food-items hook.
            const oldPath = existing.image_path ?? null;
            const newPath = updated.image_path ?? null;
            if (onImageReleased && oldPath && oldPath !== newPath) {
                const stillReferenced = await isImagePathReferenced(driver, oldPath, { kind: 'meal', id });
                if (!stillReferenced) {
                    try { await onImageReleased(oldPath); } catch { /* best-effort */ }
                }
            }
            return updated;
        },

        async delete(id: string): Promise<boolean> {
            log.debug('meals.delete', { id });
            // Capture image_path before delete so we can clean up the on-disk
            // directory after the row is gone (story 130).
            const existing = await repository.findById(id);
            const result = await driver.execute('DELETE FROM meals WHERE id = ?', id);
            const deleted = result.changes > 0;

            if (deleted && onImageReleased && existing?.image_path) {
                // The row is gone — exclude nothing; if no remaining row
                // references the path, release it.
                const stillReferenced = await isImagePathReferenced(driver, existing.image_path);
                if (!stillReferenced) {
                    try { await onImageReleased(existing.image_path); } catch { /* best-effort */ }
                }
            }
            return deleted;
        },

        async logMeal(id: string, payload: MealLogPayload): Promise<MealLogResult> {
            const meal = await repository.getById(id);
            const scale = payload.scale ?? meal.default_scale;
            const occurrenceId = uuidv7();
            const insertedIds: string[] = [];

            log.debug('meals.logMeal: BEGIN', { id, occurrenceId, date: payload.date, ingredients: meal.ingredients.length });
            await driver.execute('BEGIN TRANSACTION');
            try {
                for (const ingredient of meal.ingredients) {
                    const food = ingredient.food_item;
                    const amount = ingredient.amount * scale;
                    const macros = computeSnapshotMacros(food, amount);
                    const entryId = await insertConsumptionEntryAndRecompute(driver, {
                        date: payload.date,
                        meal_type: payload.meal_type,
                        food_item_id: food.id,
                        amount,
                        calories: macros.calories ?? undefined,
                        protein_g: macros.protein_g ?? undefined,
                        carbs_g: macros.carbs_g ?? undefined,
                        fat_g: macros.fat_g ?? undefined,
                        fiber_g: macros.fiber_g ?? undefined,
                        sugar_g: macros.sugar_g ?? undefined,
                        sodium_mg: macros.sodium_mg ?? undefined,
                        source_meal_id: meal.id,
                        meal_occurrence_id: occurrenceId,
                    });
                    insertedIds.push(entryId);
                }
                await driver.execute(
                    `UPDATE meals SET use_count = use_count + 1, last_used_at = datetime('now'), updated_at = datetime('now') WHERE id = ?`,
                    id,
                );
                await driver.execute('COMMIT');
                log.debug('meals.logMeal: COMMIT', { id, occurrenceId });
            } catch (err) {
                await driver.execute('ROLLBACK');
                log.warn('meals.logMeal: ROLLBACK', { id, occurrenceId, error: err instanceof Error ? err.message : String(err) });
                throw err;
            }

            // Read back the inserted entries (in insertion order).
            const placeholders = insertedIds.map(() => '?').join(',');
            const rows = await driver.query<ConsumptionEntry>(
                `SELECT id, date, meal_type, food_item_id, amount,
                        calories, protein_g, carbs_g, fat_g, fiber_g, sugar_g, sodium_mg,
                        source_meal_id, meal_occurrence_id, created_at, updated_at
                 FROM consumption_entries
                 WHERE id IN (${placeholders})`,
                ...insertedIds,
            );
            const byId = new Map(rows.map((r) => [r.id, r]));
            const entries = insertedIds.map((entryId) => {
                const row = byId.get(entryId);
                if (!row) throw new Error(`Inserted consumption entry ${entryId} not found after commit`);
                return row;
            });

            return { meal_occurrence_id: occurrenceId, entries };
        },
    };

    return repository;
}

export type MealRepository = ReturnType<typeof createMealRepository>;
